// ── Parse AI Agent output ────────────────────────────────────────
let jobs = [];
let parseError = null;

try {
  const raw = $('Parse Job Listings').first().json.output ?? '';

  // Guard: empty output
  if (!raw || raw.trim() === '') {
    throw new Error('Agent returned empty output. Check SerpAPI quota and OpenAI key.');
  }

  // Extract JSON array — handles any stray text the agent might add
  const arrayMatch = raw.match(/\[[\s\S]*\]/);
  if (!arrayMatch) {
    throw new Error('No JSON array in output. Agent said: ' + raw.slice(0, 400));
  }

  const parsed = JSON.parse(arrayMatch[0]);
  if (!Array.isArray(parsed)) {
    throw new Error('Parsed value is not an array.');
  }

  jobs = parsed;

} catch (e) {
  parseError = e.message;
}

// ── If parsing failed, send error report ────────────────────────
if (parseError || jobs.length === 0) {
  const agentRaw = $('Parse Job Listings').first().json.output ?? 'No output';
  const errMsg = parseError ?? 'Agent returned 0 jobs. SerpAPI may have hit quota or returned no results.';

  return [{
    json: {
      whatsapp_report: `⚠️ *PlaceRight Error*\n\n${errMsg}\n\n_Check n8n execution log for details._`,
      email_subject: 'PlaceRight — Report Failed',
      email_html: `
        <div style="font-family:Arial,sans-serif;padding:24px">
          <h2 style="color:#dc2626">⚠️ PlaceRight Report Failed</h2>
          <p><strong>Error:</strong> ${errMsg}</p>
          <h3>Raw Agent Output:</h3>
          <pre style="background:#f3f4f6;padding:16px;border-radius:6px;
                      font-size:12px;overflow-x:auto">${agentRaw}</pre>
        </div>`,
      total_jobs: 0
    }
  }];
}

// ── Date ─────────────────────────────────────────────────────────
const today = new Date().toLocaleDateString('en-IN', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

const totalFound = jobs.length;
const displayJobs = jobs.slice(0, 3); // WhatsApp 1600 char limit

// ── WhatsApp report ──────────────────────────────────────────────
let wa = `📋 *DAILY PLACEMENT REPORT*\n`;
wa += `📅 ${today}\n`;
wa += `━━━━━━━━━━━━━━━━━━\n\n`;
wa += `Found *${totalFound}* fresh opening${totalFound !== 1 ? 's' : ''} today\n`;
wa += totalFound > 3
  ? `_(Top 3 below — all ${totalFound} in your email)_\n\n`
  : `\n`;

displayJobs.forEach((job, i) => {
  const pkg  = job.package_or_stipend || 'Not disclosed';
  const reqs = (job.requirements || '').slice(0, 80);
  const hr   = job.linkedin_hr_search_query || '';
  const link = job.apply_link || '';
  const date = job.posting_date ? ` • ${job.posting_date}` : '';

  wa += `*${i + 1}. ${job.company}*${date}\n`;
  wa += `💼 ${job.role}\n`;
  wa += `📍 ${job.location}\n`;
  wa += `💰 ${pkg}\n`;
  wa += `🛠 ${reqs}…\n`;
  if (hr)   wa += `🔍 HR: _"${hr}"_ on LinkedIn\n`;
  if (link) wa += `🔗 ${link}\n`;
  wa += `─────────────────\n\n`;
});

wa += `━━━━━━━━━━━━━━━━━━\n`;
wa += `💡 *Tip:* DM the HR on LinkedIn *before* applying — 3× more visibility\n`;
wa += `\n_Sent by PlaceRight • Your AI Placement Copilot_`;

// ── Email HTML ────────────────────────────────────────────────────
let emailRows = '';
jobs.forEach((job, i) => {
  const link = job.apply_link || '#';
  const pkg  = job.package_or_stipend || '—';
  const date = job.posting_date || '—';
  const reqs = (job.requirements || '').slice(0, 80);
  const hr   = job.linkedin_hr_search_query || '—';
  const bg1  = i % 2 === 0 ? '#f9fafb' : '#ffffff';
  const bg2  = i % 2 === 0 ? '#eef2ff' : '#f0fdf4';

  emailRows += `
    <tr style="background:${bg1}">
      <td style="padding:14px 12px;font-weight:bold;color:#1e1b4b;white-space:nowrap">
        ${i + 1}. ${job.company}
      </td>
      <td style="padding:14px 12px">${job.role}</td>
      <td style="padding:14px 12px;white-space:nowrap">${job.location}</td>
      <td style="padding:14px 12px;white-space:nowrap">${pkg}</td>
      <td style="padding:14px 12px;font-size:12px;color:#374151">${reqs}…</td>
      <td style="padding:14px 12px;white-space:nowrap;font-size:12px;color:#6b7280">${date}</td>
      <td style="padding:14px 12px">
        <a href="${link}"
           style="background:#4F46E5;color:white;padding:7px 16px;border-radius:4px;
                  text-decoration:none;font-size:13px;font-weight:bold;white-space:nowrap;
                  display:inline-block">
          Apply →
        </a>
      </td>
    </tr>
    <tr style="background:${bg2}">
      <td colspan="7" style="padding:8px 12px;font-size:12px;color:#4b5563">
        🔍 Find HR on LinkedIn: <em>"${hr}"</em>
      </td>
    </tr>`;
});

const emailHtml = `
<!DOCTYPE html>
<html>
<body style="font-family:Arial,sans-serif;max-width:900px;margin:0 auto;
             color:#1a1a1a;background:#f3f4f6;padding:20px">

  <div style="background:linear-gradient(135deg,#4F46E5,#7C3AED);
              padding:28px 24px;border-radius:10px 10px 0 0">
    <h1 style="color:white;margin:0;font-size:24px">📋 Daily Placement Report</h1>
    <p style="color:#c7d2fe;margin:8px 0 0;font-size:15px">
      ${today} &nbsp;•&nbsp;
      <strong style="color:white">
        ${totalFound} fresh opening${totalFound !== 1 ? 's' : ''} found
      </strong>
    </p>
  </div>

  <div style="background:white;border:1px solid #e5e7eb;border-top:none;
              border-radius:0 0 10px 10px;overflow:hidden">

    <div style="overflow-x:auto">
      <table width="100%" cellpadding="0" cellspacing="0"
             style="border-collapse:collapse;min-width:720px">
        <thead>
          <tr style="background:#3730a3;color:white">
            <th style="padding:13px 12px;text-align:left">Company</th>
            <th style="padding:13px 12px;text-align:left">Role</th>
            <th style="padding:13px 12px;text-align:left">Location</th>
            <th style="padding:13px 12px;text-align:left">Package</th>
            <th style="padding:13px 12px;text-align:left">Key Skills</th>
            <th style="padding:13px 12px;text-align:left">Posted</th>
            <th style="padding:13px 12px;text-align:left">Link</th>
          </tr>
        </thead>
        <tbody>${emailRows}</tbody>
      </table>
    </div>

    <div style="padding:20px 24px;background:#fefce8;border-top:2px solid #fde68a">
      <p style="margin:0;font-size:14px;color:#92400e">
        💡 <strong>Pro Tip:</strong> Message the recruiter on LinkedIn
        <em>before</em> submitting your application — increases visibility 3× with the hiring team.
      </p>
    </div>

    <div style="padding:16px;background:#f3f4f6;text-align:center;
                font-size:12px;color:#9ca3af;border-top:1px solid #e5e7eb">
      Sent by <strong>PlaceRight</strong> • Your AI Placement Copilot
    </div>

  </div>
</body>
</html>`;

return [{
  json: {
    whatsapp_report: wa,
    email_subject: `📋 PlaceRight — ${totalFound} Fresh Jobs | ${today}`,
    email_html:    emailHtml,
    total_jobs:    totalFound
  }
}];

const jobs = JSON.parse($input.first().json.output);

return jobs.map((job, i) => ({
  json: {
    index: i,
    query: `${job.company} ${job.role} apply careers India`,
    original: job
  }
}));

return $input.all().map(item => {
  const results = item.json.organic_results || [];
  const original = item.json.original;

  const best = results.find(r =>
    r.link && (
      r.link.includes('careers') ||
      r.link.includes('jobs') ||
      r.link.includes('apply') ||
      r.link.includes('internship') ||
      r.link.includes(original.company.toLowerCase().replace(/\s+/g, ''))
    )
  ) || results[0];

  return {
    json: {
      ...original,
      apply_link: best?.link || null
    }
  };
});
